package genxsolution.vms.vmsbackend.vehicle_management.vehicle_model.service;
import genxsolution.vms.vmsbackend.vehicle_management.exception.VehicleResourceNotFoundException; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_model.dto.*; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_model.mapper.VehicleModelMapper; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_model.repository.VehicleModelRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class VehicleModelService { private final VehicleModelRepository repository; private final VehicleModelMapper mapper; public VehicleModelService(VehicleModelRepository repository,VehicleModelMapper mapper){this.repository=repository;this.mapper=mapper;} public List<VehicleModelResponse> list(){ return repository.findAll().stream().map(mapper::toResponse).toList(); } public VehicleModelResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new VehicleResourceNotFoundException("VehicleModel", id.toString())); } public VehicleModelResponse create(VehicleModelUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public VehicleModelResponse update(UUID id,VehicleModelUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new VehicleResourceNotFoundException("VehicleModel", id.toString())); } public void delete(UUID id){ if(!repository.delete(id)) throw new VehicleResourceNotFoundException("VehicleModel", id.toString()); } }
